 233→function parseViewBox(svgElement) {
 234→  const values = parseNumberList(svgElement.getAttribute('viewBox') || '');
 235→  if (values.length !== 4) {
 236→    return {
 237→      minX: 0,
 238→      minY: 0,
 239→      width: Number(svgElement.getAttribute('width')) || 0,
 240→      height: Number(svgElement.getAttribute('height')) || 0,
 241→    };
 242→  }
 243→  return {
 244→    minX: values[0],
 245→    minY: values[1],
 246→    width: values[2],
 247→    height: values[3],
 248→  };
 249→}
