 388→function parsePathData(pathData = '') {
 389→  const tokens = String(pathData).match(/[AaCcHhLlMmQqSsTtVvZz]|-?\d*\.?\d+(?:e[-+]?\d+)?/g) || [];
 390→  const commands = [];
 391→  let index = 0;
 392→  let current = { x: 0, y: 0 };
 393→  let subpathStart = { x: 0, y: 0 };
 394→  let command = null;
 395→
 396→  const nextNumber = () => Number(tokens[index++]);
 397→  const hasNumber = () => index < tokens.length && !/^[A-Za-z]$/.test(tokens[index]);
 398→
 399→  while (index < tokens.length) {
 400→    if (/^[A-Za-z]$/.test(tokens[index])) {
 401→      command = tokens[index++];
 402→    }
 403→    if (!command) break;
 404→
 405→    switch (command) {
 406→      case 'M':
 407→      case 'm': {
 408→        while (hasNumber()) {
 409→          const x = nextNumber();
 410→          const y = nextNumber();
 411→          current = command === 'm'
 412→            ? { x: current.x + x, y: current.y + y }
 413→            : { x, y };
 414→          commands.push({ type: 'M', x: current.x, y: current.y });
 415→          subpathStart = { ...current };
 416→          command = command === 'm' ? 'l' : 'L';
 417→        }
 418→        break;
 419→      }
 420→      case 'L':
 421→      case 'l':
 422→        while (hasNumber()) {
 423→          const x = nextNumber();
 424→          const y = nextNumber();
 425→          current = command === 'l'
 426→            ? { x: current.x + x, y: current.y + y }
 427→            : { x, y };
 428→          commands.push({ type: 'L', x: current.x, y: current.y });
 429→        }
 430→        break;
 431→      case 'H':
 432→      case 'h':
 433→        while (hasNumber()) {
 434→          const x = nextNumber();
 435→          current = command === 'h'
 436→            ? { x: current.x + x, y: current.y }
 437→            : { x, y: current.y };
 438→          commands.push({ type: 'L', x: current.x, y: current.y });
 439→        }
 440→        break;
 441→      case 'V':
 442→      case 'v':
 443→        while (hasNumber()) {
 444→          const y = nextNumber();
 445→          current = command === 'v'
 446→            ? { x: current.x, y: current.y + y }
 447→            : { x: current.x, y };
 448→          commands.push({ type: 'L', x: current.x, y: current.y });
 449→        }
 450→        break;
 451→      case 'A':
 452→      case 'a':
 453→        while (hasNumber()) {
 454→          const rx = nextNumber();
 455→          const ry = nextNumber();
 456→          const rotation = nextNumber();
 457→          const largeArcFlag = nextNumber();
 458→          const sweepFlag = nextNumber();
 459→          const xValue = nextNumber();
 460→          const yValue = nextNumber();
 461→          const end = command === 'a'
 462→            ? { x: current.x + xValue, y: current.y + yValue }
 463→            : { x: xValue, y: yValue };
 464→          const arcPoints = buildArcPoints(current, rx, ry, rotation, largeArcFlag, sweepFlag, end);
 465→          for (const point of arcPoints) {
 466→            commands.push({ type: 'L', x: point.x, y: point.y });
 467→          }
 468→          current = end;
 469→        }
 470→        break;
 471→      case 'Z':
 472→      case 'z':
 473→        commands.push({ type: 'Z' });
 474→        current = { ...subpathStart };
 475→        break;
 476→      default:
 477→        index = tokens.length;
 478→        break;
 479→    }
 480→  }
 481→
 482→  return commands;
 483→}
 484→
 485→function emitPathFromPoints(builder, points, closePath) {
 486→  if (!points.length) return;
 487→  builder.write(`${fmt(points[0].x)} ${fmt(points[0].y)} m`);
 488→  for (let index = 1; index < points.length; index += 1) {
 489→    builder.write(`${fmt(points[index].x)} ${fmt(points[index].y)} l`);
 490→  }
 491→  if (closePath) builder.write('h');
 492→}
