 494→class PdfBuilder {
 495→  constructor(pageWidthPt, pageHeightPt) {
 496→    this.pageWidthPt = pageWidthPt;
 497→    this.pageHeightPt = pageHeightPt;
 498→    this.content = [];
 499→    this.alphaMap = new Map();
 500→    this.images = [];
 501→  }
 502→
 503→  write(line) {
 504→    this.content.push(`${line}\n`);
 505→  }
 506→
 507→  alphaName(fillOpacity, strokeOpacity) {
 508→    const fill = Math.max(0, Math.min(1, fillOpacity));
 509→    const stroke = Math.max(0, Math.min(1, strokeOpacity));
 510→    if (fill >= 0.999 && stroke >= 0.999) return null;
 511→    const key = `${fill.toFixed(3)}:${stroke.toFixed(3)}`;
 512→    if (!this.alphaMap.has(key)) {
 513→      this.alphaMap.set(key, {
 514→        name: `GS${this.alphaMap.size + 1}`,
 515→        fill,
 516→        stroke,
 517→      });
 518→    }
 519→    return this.alphaMap.get(key).name;
 520→  }
 521→
 522→  applyStyle(style, { fillAllowed = true, strokeAllowed = true } = {}) {
 523→    if (strokeAllowed && style.stroke && style.strokeWidth > 0) {
 524→      this.write(`${fmt(style.stroke[0])} ${fmt(style.stroke[1])} ${fmt(style.stroke[2])} RG`);
 525→      this.write(`${fmt(style.strokeWidth)} w`);
 526→      this.write(`${lineCapCode(style.lineCap)} J`);
 527→      this.write(`${lineJoinCode(style.lineJoin)} j`);
 528→      if (style.dashArray.length) {
 529→        this.write(`[${style.dashArray.map(fmt).join(' ')}] 0 d`);
 530→      } else {
 531→        this.write('[] 0 d');
 532→      }
 533→    }
 534→
 535→    if (fillAllowed && style.fill) {
 536→      this.write(`${fmt(style.fill[0])} ${fmt(style.fill[1])} ${fmt(style.fill[2])} rg`);
 537→    }
 538→
 539→    const alphaName = this.alphaName(
 540→      fillAllowed ? style.fillOpacity : 1,
 541→      strokeAllowed ? style.strokeOpacity : 1
 542→    );
 543→    if (alphaName) {
 544→      this.write(`/${alphaName} gs`);
 545→    }
 546→  }
 547→
 548→  addImage(jpegBytes, pixelWidth, pixelHeight) {
 549→    const name = `Im${this.images.length + 1}`;
 550→    this.images.push({ name, jpegBytes, pixelWidth, pixelHeight });
 551→    return name;
 552→  }
 553→
 554→  finish() {
 555→    const encoder = new TextEncoder();
 556→    const contentStream = encoder.encode(this.content.join(''));
 557→    const alphaObjects = [...this.alphaMap.values()];
 558→    const fontObjectNumber = 4;
 559→    const firstAlphaObjectNumber = 5;
 560→    const firstImageObjectNumber = firstAlphaObjectNumber + alphaObjects.length;
 561→    const contentObjectNumber = firstImageObjectNumber + this.images.length;
 562→    const totalObjects = contentObjectNumber;
 563→    const objects = [];
 564→
 565→    objects[1] = encoder.encode('1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n');
 566→    objects[2] = encoder.encode('2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n');
 567→
 568→    const extGStateEntries = alphaObjects
 569→      .map((entry, index) => `/${entry.name} ${firstAlphaObjectNumber + index} 0 R`)
 570→      .join(' ');
 571→
 572→    const xObjectEntries = this.images
 573→      .map((entry, index) => `/${entry.name} ${firstImageObjectNumber + index} 0 R`)
 574→      .join(' ');
 575→
 576→    let resources = `/Font << /F1 ${fontObjectNumber} 0 R >>`;
 577→    if (extGStateEntries) resources += ` /ExtGState << ${extGStateEntries} >>`;
 578→    if (xObjectEntries) resources += ` /XObject << ${xObjectEntries} >>`;
 579→
 580→    objects[3] = encoder.encode(
 581→      `3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${fmt(this.pageWidthPt)} ${fmt(this.pageHeightPt)}] /Resources << ${resources} >> /Contents ${contentObjectNumber} 0 R >>\nendobj\n`
 582→    );
 583→    objects[4] = encoder.encode('4 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n');
 584→
 585→    alphaObjects.forEach((entry, index) => {
 586→      objects[firstAlphaObjectNumber + index] = encoder.encode(
 587→        `${firstAlphaObjectNumber + index} 0 obj\n<< /Type /ExtGState /ca ${fmt(entry.fill)} /CA ${fmt(entry.stroke)} >>\nendobj\n`
 588→      );
 589→    });
 590→
 591→    this.images.forEach((entry, index) => {
 592→      const objNum = firstImageObjectNumber + index;
 593→      const headerBytes = encoder.encode(
 594→        `${objNum} 0 obj\n<< /Type /XObject /Subtype /Image /Width ${entry.pixelWidth} /Height ${entry.pixelHeight} /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${entry.jpegBytes.length} >>\nstream\n`
 595→      );
 596→      const footerBytes = encoder.encode('\nendstream\nendobj\n');
 597→      const combined = new Uint8Array(headerBytes.length + entry.jpegBytes.length + footerBytes.length);
 598→      combined.set(headerBytes, 0);
 599→      combined.set(entry.jpegBytes, headerBytes.length);
 600→      combined.set(footerBytes, headerBytes.length + entry.jpegBytes.length);
 601→      objects[objNum] = combined;
 602→    });
 603→
 604→    const contentHeader = encoder.encode(
 605→      `${contentObjectNumber} 0 obj\n<< /Length ${contentStream.length} >>\nstream\n`
 606→    );
 607→    const contentFooter = encoder.encode('endstream\nendobj\n');
 608→    objects[contentObjectNumber] = new Uint8Array(contentHeader.length + contentStream.length + contentFooter.length);
 609→    objects[contentObjectNumber].set(contentHeader, 0);
 610→    objects[contentObjectNumber].set(contentStream, contentHeader.length);
 611→    objects[contentObjectNumber].set(contentFooter, contentHeader.length + contentStream.length);
 612→
 613→    const header = encoder.encode('%PDF-1.4\n');
 614→    const binaryComment = new Uint8Array([0x25, 0xe2, 0xe3, 0xcf, 0xd3, 0x0a]);
 615→    const offsets = [0];
 616→    let offset = header.length + binaryComment.length;
 617→
 618→    for (let index = 1; index <= totalObjects; index += 1) {
 619→      offsets[index] = offset;
 620→      offset += objects[index].length;
 621→    }
 622→
 623→    const xrefStart = offset;
 624→    let xref = `xref\n0 ${totalObjects + 1}\n0000000000 65535 f \n`;
 625→    for (let index = 1; index <= totalObjects; index += 1) {
 626→      xref += `${String(offsets[index]).padStart(10, '0')} 00000 n \n`;
 627→    }
 628→    const trailer = `trailer\n<< /Size ${totalObjects + 1} /Root 1 0 R >>\nstartxref\n${xrefStart}\n%%EOF`;
 629→
 630→    return new Blob(
 631→      [header, binaryComment, ...objects.slice(1), encoder.encode(xref), encoder.encode(trailer)],
 632→      { type: 'application/pdf' }
 633→    );
 634→  }
 635→}
