 870→function renderRect(builder, element) {
 871→  const x = Number(element.getAttribute('x')) || 0;
 872→  const y = Number(element.getAttribute('y')) || 0;
 873→  const width = Number(element.getAttribute('width')) || 0;
 874→  const height = Number(element.getAttribute('height')) || 0;
 875→  const style = computeStyle(element);
 876→
 877→  builder.write('q');
 878→  builder.applyStyle(style);
 879→  builder.write(`${fmt(x)} ${fmt(y)} ${fmt(width)} ${fmt(height)} re`);
 880→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
 881→  else if (style.fill) builder.write('f');
 882→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
