 902→function renderPath(builder, element) {
 903→  const commands = parsePathData(element.getAttribute('d') || '');
 904→  if (!commands.length) return;
 905→  const style = computeStyle(element);
 906→
 907→  builder.write('q');
 908→  builder.applyStyle(style);
 909→  for (const command of commands) {
 910→    if (command.type === 'M') builder.write(`${fmt(command.x)} ${fmt(command.y)} m`);
 911→    else if (command.type === 'L') builder.write(`${fmt(command.x)} ${fmt(command.y)} l`);
 912→    else if (command.type === 'Z') builder.write('h');
 913→  }
 914→
 915→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
 916→  else if (style.fill) builder.write('f');
 917→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
 918→  builder.write('Q');
 919→}
