 5→export function wallOutline(wall) {
 6→  const dir = normalize(subtract(wall.end, wall.start));
 7→  const perp = perpendicular(dir);
 8→  const halfThick = wall.thickness / 2;
 9→  const offset = scale(perp, halfThick);
10→
11→  return [
12→    add(wall.start, offset),
13→    add(wall.end, offset),
14→    subtract(wall.end, offset),
15→    subtract(wall.start, offset),
16→  ];
17→}
